// Lissajous Lab - Oscilloscope VJ Visuals

let prevType = '';
let globalAngle = 0;

const PALETTES = {
  phosphor_green: [[0,255,65],[0,200,50],[0,150,40],[50,255,100],[0,180,55]],
  oscilloscope: [[0,255,100],[0,200,255],[100,255,200],[50,255,150],[0,230,180]],
  neon: [[255,0,150],[0,255,200],[255,100,0],[200,0,255],[0,200,255]],
  laser: [[255,0,0],[0,255,0],[0,100,255],[255,0,0],[0,255,0]],
  synthwave: [[255,0,100],[0,200,255],[255,100,200],[100,0,255],[255,50,150]],
  rainbow: [[255,0,0],[255,200,0],[0,255,0],[0,200,255],[180,0,255]],
  plasma: [[255,50,0],[200,0,200],[0,100,255],[255,200,0],[200,50,255]],
  monochrome: [[255,255,255],[200,200,200],[150,150,150],[230,230,230],[180,180,180]]
};

function getFreqPair(ratio) {
  const m = {
    unison: [1, 1],
    octave: [1, 2],
    fifth: [2, 3],
    third: [3, 4],
    seventh: [4, 7],
    detuned: [1, 1.01]
  };
  return m[ratio] || [1, 2];
}

function getPhase(v, t) {
  if (v === 'zero') return 0;
  if (v === 'quarter') return Math.PI / 2;
  if (v === 'third') return Math.PI / 3;
  if (v === 'half') return Math.PI;
  if (v === 'sweep') return t * 0.01;
  if (v === 'random') return Math.sin(t * 0.03) * Math.PI;
  return 0;
}

function getTrailN(v) {
  const m = {single:1, few:3, several:6, many:10, cascade:16, dense:24};
  return m[v] || 3;
}

function getLineW(v) {
  const m = {hairline:1, fine:1.5, medium:2.5, bold:4, heavy:6, variable:-1};
  return m[v] || 1.5;
}

function getRotSpeed(v) {
  const m = {frozen:0, slow:0.005, medium:0.015, fast:0.035, oscillating:-1, chaotic:-2};
  return m[v] || 0.005;
}

function samplePalette(pal, t) {
  t = ((t % 1) + 1) % 1;
  let idx = t * (pal.length - 1);
  let i = Math.floor(idx);
  let f = idx - i;
  let c1 = pal[Math.min(i, pal.length - 1)];
  let c2 = pal[Math.min(i + 1, pal.length - 1)];
  return [c1[0]+(c2[0]-c1[0])*f, c1[1]+(c2[1]-c1[1])*f, c1[2]+(c2[2]-c1[2])*f];
}

p.setup = function() {
  p.createCanvas(600, 600);
  p.frameRate(30);
  p.background(0);
};

p.draw = function() {
  let figV = p.getSynthVar('figure_type') || 'classic';
  let ratioV = p.getSynthVar('freq_ratio') || 'octave';
  let phaseV = p.getSynthVar('phase_shift') || 'quarter';
  let trailNV = p.getSynthVar('trail_count') || 'few';
  let trailMV = p.getSynthVar('trail_mode') || 'fade';
  let lwV = p.getSynthVar('line_weight') || 'fine';
  let palV = p.getSynthVar('color_palette') || 'phosphor_green';
  let cmodeV = p.getSynthVar('color_mode') || 'angle';
  let rotV = p.getSynthVar('rotation_speed') || 'slow';
  let modV = p.getSynthVar('modulation') || 'none';

  let configKey = figV + ratioV + phaseV + trailNV + palV + cmodeV;
  if (configKey !== prevType) {
    prevType = configKey;
    p.background(0);
    globalAngle = 0;
  }

  let palette = PALETTES[palV] || PALETTES.phosphor_green;
  let nTrails = getTrailN(trailNV);
  let lw = getLineW(lwV);
  let rotSpeed = getRotSpeed(rotV);
  let freqs = getFreqPair(ratioV);
  let phase = getPhase(phaseV, p.frameCount);

  // Background handling
  if (trailMV === 'solid') {
    p.background(0);
  } else if (trailMV === 'fade') {
    p.fill(0, 0, 0, 12);
    p.noStroke();
    p.rect(0, 0, 600, 600);
  } else if (trailMV === 'phosphor') {
    p.fill(0, 0, 0, 6);
    p.noStroke();
    p.rect(0, 0, 600, 600);
  } else if (trailMV === 'strobe') {
    if (p.frameCount % 8 < 2) p.background(0);
  } else if (trailMV === 'echo') {
    p.fill(0, 0, 0, 20);
    p.noStroke();
    p.rect(0, 0, 600, 600);
  }
  // infinite = no clearing

  // Rotation
  if (rotSpeed === -1) {
    globalAngle = Math.sin(p.frameCount * 0.01) * 1.5;
  } else if (rotSpeed === -2) {
    globalAngle += Math.sin(p.frameCount * 0.02) * 0.02;
  } else {
    globalAngle += rotSpeed;
  }

  // Modulation
  let modAmp = 0;
  let modFreq = 0;
  if (modV === 'vibrato') { modAmp = 0.02; modFreq = 5; }
  else if (modV === 'tremolo') { modAmp = 0.3; modFreq = 3; }
  else if (modV === 'wobble') { modAmp = 0.1; modFreq = 0.7; }
  else if (modV === 'glitch') { modAmp = Math.random() > 0.95 ? 0.5 : 0; modFreq = 20; }
  else if (modV === 'breathe') { modAmp = 0.15; modFreq = 0.3; }

  let modVal = modAmp * Math.sin(p.frameCount * modFreq * 0.05);

  let cx = 300, cy = 300;
  let baseRadius = 220;

  for (let layer = 0; layer < nTrails; layer++) {
    let layerOffset = layer * Math.PI * 2 / nTrails;
    let layerPhase = phase + layerOffset * 0.3;
    let radius = baseRadius * (1 - layer * 0.02);

    let fA = freqs[0] + modVal;
    let fB = freqs[1];

    let points = 600;
    let prevX, prevY;

    for (let i = 0; i <= points; i++) {
      let t = i / points * Math.PI * 2;
      let x, y;

      if (figV === 'classic') {
        x = Math.sin(fA * t + layerPhase + p.frameCount * 0.02);
        y = Math.sin(fB * t + p.frameCount * 0.02);
      } else if (figV === 'rose') {
        let k = fA / fB;
        let r = Math.cos(k * t + p.frameCount * 0.02);
        x = r * Math.cos(t + layerPhase);
        y = r * Math.sin(t + layerPhase);
      } else if (figV === 'spirograph') {
        let R = 1, rr = fA / (fA + fB), d = 0.8;
        let inner = t * fB / fA + p.frameCount * 0.02;
        x = (R - rr) * Math.cos(t + layerPhase) + d * Math.cos(inner);
        y = (R - rr) * Math.sin(t + layerPhase) - d * Math.sin(inner);
        x *= 0.6; y *= 0.6;
      } else if (figV === 'harmonograph') {
        let decay = Math.exp(-t * 0.05);
        x = Math.sin(fA * t + layerPhase + p.frameCount * 0.02) * decay;
        y = Math.sin(fB * t + Math.PI/4 + p.frameCount * 0.015) * decay;
      } else if (figV === 'butterfly') {
        let bt = t + p.frameCount * 0.01;
        let r = Math.exp(Math.cos(bt)) - 2 * Math.cos(4 * bt) + Math.pow(Math.sin(bt / 12), 5);
        x = Math.sin(bt + layerPhase) * r * 0.25;
        y = Math.cos(bt + layerPhase) * r * 0.25;
      } else { // lemniscate
        let lt = t + p.frameCount * 0.02;
        let denom = 1 + Math.sin(lt) * Math.sin(lt);
        x = Math.cos(lt + layerPhase) / denom;
        y = Math.sin(lt + layerPhase) * Math.cos(lt) / denom;
      }

      // Apply rotation
      let rx = x * Math.cos(globalAngle) - y * Math.sin(globalAngle);
      let ry = x * Math.sin(globalAngle) + y * Math.cos(globalAngle);

      let px = cx + rx * radius;
      let py = cy + ry * radius;

      if (i > 0) {
        // Color
        let colorT = 0;
        if (cmodeV === 'angle') colorT = t / (Math.PI * 2);
        else if (cmodeV === 'speed') {
          let dx = px - prevX, dy = py - prevY;
          colorT = Math.sqrt(dx*dx + dy*dy) * 0.02;
        }
        else if (cmodeV === 'layer') colorT = layer / nTrails;
        else if (cmodeV === 'time') colorT = (p.frameCount * 0.005 + layer * 0.1) % 1;
        else if (cmodeV === 'distance') colorT = Math.sqrt(rx*rx + ry*ry);
        else colorT = (fA * t) % 1;

        let col = samplePalette(palette, colorT);
        let alpha = 180 - layer * (120 / nTrails);
        if (trailMV === 'phosphor') alpha = Math.min(255, alpha + 40);

        let w = lw === -1 ? (1 + Math.abs(Math.sin(t * 3)) * 4) : lw;

        p.stroke(col[0], col[1], col[2], alpha);
        p.strokeWeight(w * (1 - layer * 0.03));
        p.line(prevX, prevY, px, py);

        // Glow for phosphor_green and oscilloscope palettes
        if (palV === 'phosphor_green' || palV === 'oscilloscope') {
          p.stroke(col[0], col[1], col[2], alpha * 0.15);
          p.strokeWeight(w * 3);
          p.line(prevX, prevY, px, py);
        }
      }

      prevX = px;
      prevY = py;
    }
  }
};
